output.sparql:
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX ps: <http://www.wikidata.org/prop/statement/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX pq: <http://www.wikidata.org/prop/qualifier/>
SELECT ?athlete ?medalLabel ?athleteLabel ?sortKey WHERE {
  VALUES ?event {
    wd:Q47295100
  }
  VALUES(?medal ?medalLabel ?sortKey) {(wd:Q35306 "Gold" 1)(wd:Q35305 "Silver" 2)(wd:Q35304 "Bronze" 3)
  }
  ?athlete p:P166 ?statement .
  ?statement ps:P166 ?medal .
  ?statement pq:P3450 ?event .
  OPTIONAL {
    ?athlete rdfs:label ?athleteLabel
    FILTER(LANG(?athleteLabel) = "en")
  }
}
ORDER BY ?sortKey
